mapper.sql:
WHERE p.latitude IS NOT NULL
  AND p.longitude IS NOT NULL
  AND p.latitude BETWEEN #{request.swLat} AND #{request.neLat}
  AND p.longitude BETWEEN #{request.swLng} AND #{request.neLng}

WHERE 1 = 1



    AND p.sido = #{request.sido}


    AND p.sigungu = #{request.sigungu}


    AND p.legal_dong = #{request.legalDong}


    AND p.name LIKE CONCAT('%', #{request.complexName}, '%')


    AND (
        p.name LIKE CONCAT('%', #{request.keyword}, '%')
        OR p.road_address LIKE CONCAT('%', #{request.keyword}, '%')
        OR p.jibun_address LIKE CONCAT('%', #{request.keyword}, '%')
        OR p.legal_dong LIKE CONCAT('%', #{request.keyword}, '%')
    )


    AND p.latitude BETWEEN #{request.swLat} AND #{request.neLat}
    AND p.longitude BETWEEN #{request.swLng} AND #{request.neLng}

mapper.select:
SELECT property_type
FROM properties
WHERE property_id = #{propertyId}
